// NewRSSParser creates a new RSS parser instance
func NewRSSParser() *RSSParser {
	return &RSSParser{}
}

// Parse converts an RSS feed from io.Reader to UniversalFeed
func (p *RSSParser) Parse(r io.Reader) (*models.UniversalFeed, error) {
	feed := &models.UniversalFeed{
		Items: make([]*models.UniversalItem, 0),
	}

	// Decode the XML
	decoder := xml.NewDecoder(r)

	// Start parsing RSS structure
	startElement, err := decoder.Token()
	if err != nil {
		return nil, err
